1	function countLiveNeighbors(
2	  livingCells: Set<string>,
3	  x: number,
4	  y: number
5	): number {
6	  let neighbors = 0;
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      if (livingCells.has(`${x + dx},${y + dy}`)) neighbors++;
11	    }
12	  }
13	  return neighbors;
14	}
15	
16	export function nextGeneration(livingCells: Set<string>): Set<string> {
17	  const result = new Set<string>();
18	  for (const cell of livingCells) {
19	    const [x, y] = cell.split(",").map(Number);
20	    if (countLiveNeighbors(livingCells, x, y) === 2) result.add(cell);
21	  }
22	  return result;
23	}
